const fs = require('fs');
const https = require('https');
const db = require('./db');

function processFiles(dir, options, callback) {
    fs.readdir(dir, function(err, files) {
        if (err) return callback(err);
        var results = [];
        var pending = files.length;
        if (!pending) return callback(null, results);

        files.forEach(function(file) {
            var filepath = dir + '/' + file;
            fs.stat(filepath, function(err, stat) {
                if (err) { pending--; return; }
                if (stat.isDirectory()) {
                    processFiles(filepath, options, function(err, res) {
                        results = results.concat(res || []);
                        if (!--pending) callback(null, results);
                    });
                } else {
                    fs.readFile(filepath, 'utf8', function(err, content) {
                        if (err) { pending--; return; }
                        if (options.validate) {
                            https.get(options.validateUrl + '?content=' + encodeURIComponent(content), function(res) {
                                var body = '';
                                res.on('data', function(chunk) { body += chunk; });
                                res.on('end', function() {
                                    var valid = JSON.parse(body).valid;
                                    if (valid) {
                                        db.save(filepath, content, function(err) {
                                            if (!err) results.push({path: filepath, size: stat.size});
                                            if (!--pending) callback(null, results);
                                        });
                                    } else {
                                        if (!--pending) callback(null, results);
                                    }
                                });
                            }).on('error', function() {
                                if (!--pending) callback(null, results);
                            });
                        } else {
                            db.save(filepath, content, function(err) {
                                if (!err) results.push({path: filepath, size: stat.size});
                                if (!--pending) callback(null, results);
                            });
                        }
                    });
                }
            });
        });
    });
}
